using Microsoft.EntityFrameworkCore;

// Cosmos DB context showing required EF Core 9 breaking-change fixes.
class CosmosContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();

    protected override void OnConfiguring(DbContextOptionsBuilder options)
        => options.UseCosmos(
            "AccountEndpoint=https://localhost:8081/;AccountKey=key",
            "CatalogDb");

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // FIX #4 – EF Core 9 changed the default discriminator property
        // from "Discriminator" to "$type". Existing Cosmos documents still
        // use "Discriminator", so we must opt back in to the old name.
        modelBuilder.Entity<Product>()
            .HasDiscriminator<string>("Discriminator");

        modelBuilder.Entity<Product>()
            .ToContainer("Products")
            .HasPartitionKey(p => p.Category);
    }
}

class Product
{
    public string Id { get; set; } = default!;
    public string Name { get; set; } = default!;
    public string Category { get; set; } = default!;
}

// FIX #5 – EF Core 9 Cosmos provider removed sync-over-async support.
// All calls like ToList(), First(), SaveChanges() now throw.
// Replace every synchronous call with its async equivalent.
class ProductService
{
    // BEFORE (EF Core 8 — now throws InvalidOperationException):
    //   var products = db.Products.ToList();
    //   db.SaveChanges();

    // AFTER (EF Core 9):
    async Task<List<Product>> GetAllAsync(CosmosContext db)
        => await db.Products.ToListAsync();

    async Task AddAsync(CosmosContext db, Product product)
    {
        db.Products.Add(product);
        await db.SaveChangesAsync();
    }
}

